import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Cookies from "js-cookie";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import copy from "copy-to-clipboard";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function UserDetails() {
  const { userId } = useParams();
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [payments, setPayments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("profile");

  // =================== COPY TO CLIPBOARD ===================
  const handleCopy = (text, label) => {
    if (copy(text)) toast.success(`${label} copied to clipboard`);
    else toast.error(`Failed to copy ${label}`);
  };

  // =================== FETCH USER & PAYMENTS ===================
  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) {
      navigate("/");
      return;
    }

    setLoading(true);

    axios
      .get(`${API_BASE_URL}/users/${userId}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setUser(res.data.data);
        else toast.error(res.data.error || "Failed to fetch user");
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching user"),
      );

    axios
      .get(`${API_BASE_URL}/users/${userId}/payments`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setPayments(res.data.data);
        else toast.error(res.data.error || "Failed to fetch payments");
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching payments"),
      )
      .finally(() => setLoading(false));
  }, [userId, navigate]);

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (!user) return <div className="text-center mt-5">No user found</div>;

  return (
    <div className="container mt-3">
      <Toast />

      {/* Back Button */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate(-1)}
          ></i>
        </div>
      </div>

      {/* Header & Tabs */}
      <div className="row g-3 mb-3">
        <div className="col-md-4">
          <h4 className="fw-bold mb-0">User Profile</h4>
        </div>

        <div className="col-md-8 d-flex justify-content-md-end">
          <ul className="nav nav-tabs">
            <li className="nav-item">
              <button
                className={`nav-link ${
                  activeTab === "profile" ? "active" : ""
                }`}
                onClick={() => setActiveTab("profile")}
              >
                Profile
              </button>
            </li>

            <li className="nav-item">
              <button
                className={`nav-link ${
                  activeTab === "payments" ? "active" : ""
                }`}
                onClick={() => setActiveTab("payments")}
              >
                Payments
              </button>
            </li>
          </ul>
        </div>
      </div>

      {/* ================= PROFILE TAB ================= */}
{activeTab === "profile" && (
  <div className="card mb-4" style={{
    background: "rgba(255, 255, 255, 0.2)",
    backdropFilter: "blur(15px)",
    borderRadius: "20px",
    border: "1px solid rgba(255, 255, 255, 0.3)",
    boxShadow: "0 8px 32px rgba(0,0,0,0.1)"
  }}>
    <div className="card-body p-4 text-center">
      <div className="mb-3">
        <div className="rounded-circle bg-primary text-white d-inline-flex align-items-center justify-content-center" 
             style={{width: "80px", height: "80px", fontSize: "30px"}}>
          {user.fullName?.charAt(0)}
        </div>
      </div>
      <h4 className="fw-bold">{user.prefix} {user.fullName}</h4>
      <span className={`badge ${user.status==="active"?"bg-success":"bg-secondary"}`}>{user.status}</span>

      <div className="mt-4 text-start">
        <p><strong>Email:</strong> {user.email} <i className="fa-solid fa-copy ms-2 text-primary" style={{cursor:"pointer"}} onClick={()=>handleCopy(user.email,"Email")}></i></p>
        <p><strong>Phone:</strong> {user.phone} <i className="fa-solid fa-copy ms-2 text-primary" style={{cursor:"pointer"}} onClick={()=>handleCopy(user.phone,"Phone")}></i></p>
        <p><strong>Source:</strong> {user.source || "N/A"}</p>
        {user.employeeId && <p><strong>Employee:</strong> {user.employeeName} <i className="fa-solid fa-copy ms-2 text-primary" style={{cursor:"pointer"}} onClick={()=>handleCopy(user.employeeName,"Employee")}></i></p>}
      </div>
    </div>
  </div>
)}


      {/* ================= PAYMENTS TAB ================= */}
      {activeTab === "payments" && (
        <div className="card">
          <div className="card-body">
            <h5 className="card-title">Payments</h5>

            {payments.length > 0 ? (
              <div className="table-responsive rounded">
                <table className="table table-striped table-hover small">
                  <thead className="table-dark">
                    <tr>
                      <th>ID</th>
                      <th>Total</th>
                      <th>Paid</th>
                      <th>Remaining</th>
                      <th>Method</th>
                      <th>Status</th>
                      <th>Transaction ID</th>
                      <th>Payment Date</th>
                    </tr>
                  </thead>
                  <tbody>
                    {payments.map((p) => (
                      <tr key={p.id}>
                        <td style={{ minWidth: "50px" }}>{p.id}</td>
                        <td style={{ minWidth: "120px" }}>{p.totalAmount}</td>
                        <td style={{ minWidth: "120px" }}>{p.paidAmount}</td>
                        <td style={{ minWidth: "130px" }}>
                          {p.remainingAmount}
                        </td>
                        <td style={{ minWidth: "140px" }}>{p.paymentMethod}</td>
                        <td style={{ minWidth: "100px" }}>{p.status}</td>
                        <td style={{ minWidth: "180px" }}>
                          {p.transactionId}{" "}
                          {p.transactionId && (
                            <i
                              className="fa-solid fa-copy ms-2"
                              style={{ cursor: "pointer" }}
                              onClick={() =>
                                handleCopy(p.transactionId, "Transaction ID")
                              }
                            ></i>
                          )}
                        </td>
                        <td style={{ minWidth: "200px" }}>
                          {dayjs(p.paymentDate).format("DD MMM YYYY, hh:mm A")}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <p>No payments found for this user.</p>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default UserDetails;
